INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-01', 'قتل', 'جريمة في الفيلا الزجاجية', 'أثناء عشاء خاص في فيلا فاخرة، يُعثر على صاحب المنزل مقتولًا داخل مكتبه بعد انقطاع كهربائي قصير.', 5, 2, 'سليم، عادل', 'انقطاع كهرباء أقل من دقيقة؛ أكثر من شخص شوهد قرب الممر المؤدي للمكتب؛ الضحية كان ينتظر نقاشًا خاصًا بعد العشاء.', 'أحد الحاضرين كان يبحث عن مستند داخل المكتب؛ شخص أخفى مروره بالممر الشرقي؛ قرار مالي أو ميراثي كان سيتغير الليلة نفسها.', 'قطعة زجاج قرب باب المكتب؛ روايات غير متطابقة عن الخروج من غرفة الطعام؛ أكثر من شخص يعرف أن كاميرا الخدمة ضعيفة.', 'عادل خلق لحظة الارتباك عبر الكهرباء، وسليم دخل المكتب وقتل الضحية لمنع كشف تلاعب مالي بينهما.', 'ريم كانت تبحث عن وصية جديدة؛ نادر أراد إخفاء ورقة قانونية محرجة؛ يارا أخفت رسالة شخصية قديمة.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-02', 'قتل', 'آخر مكالمة', 'رجل أعمال يُقتل داخل سيارته بعد مكالمة هاتفية متوترة، دون كسر أو سرقة.', 5, 2, 'مازن، فؤاد', 'الضحية توقع مقابلة شخص يعرفه؛ السيارة كانت مغلقة؛ أكثر من شخص يعلم مكان توقفها المعتاد.', 'أحد المقربين حذف سجل مكالمة؛ شخص كذب عن توقيت مغادرته؛ قرار كبير كان سيضر بمصالح عدة أطراف صباح اليوم التالي.', 'آثار تراب داخل السيارة؛ اختلاف حول آخر من تواصل معه فعليًا؛ اثنان على الأقل أخفيا لقاءهما بالضحية قبل الحادثة.', 'مازن رتب المواجهة الأخيرة لأن الضحية كان سيكشف احتيالًا ماليًا، وفؤاد استغل قربه من السيارة ونفذ الجريمة.', 'دينا حذفت رسالة شخصية؛ سامح كان قد هدده شفهيًا؛ هدى كانت تعلم أنه سيغيّر وصيته.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-03', 'قتل', 'موت على المسرح', 'ممثل رئيسي يسقط ميتًا أثناء عرض مسرحي مباشر بعد تغيير خلف الكواليس.', 5, 2, 'شريف، حسام', 'الجريمة مرتبطة بأداة أو عنصر من العرض؛ عدة أشخاص لديهم وصول للمشهد الأخير؛ الضحية على خلاف مهني مع أكثر من فرد.', 'أحد أفراد الطاقم دخل غرفة الإكسسوارات سرًا؛ شخص آخر عرف مشكلة فنية ولم يبلغ؛ الضحية كان ينوي استبدال أحد أعضاء الفريق.', 'قطعة من تجهيزات المشهد في غير مكانها؛ روايات متناقضة عن الدقائق الأخيرة؛ توتر شديد عند سؤال أحدهم عن التعديل الأخير.', 'شريف دبّر الجريمة لأن الضحية كان سيكشف فضيحة تخصه، وحسام نفذ التعديل في عناصر العرض.', 'ليلى كانت تغار فنيًا؛ مريم أخفت أزمة تمويل؛ باسم كان ينتظر فرصة البطولة.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-04', 'قتل', 'الجثة في القارب', 'يُعثر على شاب مقتولًا داخل قارب صغير بعد سهرة ليلية.', 3, 1, 'يونس', 'القارب تحرك مرة إضافية بعد السهرة؛ الضحية دخل في نقاش حاد مع أكثر من شخص؛ الفاعل يعرف تشغيل القارب والتحرك حوله.', 'أحد الموجودين كذب بشأن توقيت مغادرته الضفة؛ شخص آخر أخفى خلافًا ماليًا قديمًا؛ الضحية احتفظ بشيء يخص أحد أصدقائه.', 'آثار مبللة داخل سيارة أحدهم؛ رواية غير مستقرة حول آخر من تحدث مع الضحية؛ شيء مفقود من القارب قد يكون له صلة بالجريمة أو بخلاف جانبي.', 'يونس عاد مع الضحية إلى القارب بعد مشادة حول دين قديم وأمر شخصي حساس ثم قتله هناك.', 'كريم أخذ مبلغًا صغيرًا من الضحية؛ تامر أخفى أنه تشاجر معه لفظيًا.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-05', 'قتل', 'مقتل الشريك الصامت', 'قبل توقيع صفقة كبيرة، يُقتل أحد الشركاء داخل مقر الشركة.', 5, 2, 'أدهم، فريدة', 'الضحية كان يرفض تمرير الصفقة؛ عدة أشخاص يعرفون بوجود ملفات حساسة داخل مكتبه؛ توقيت الجريمة استغل اجتماعًا رسميًا.', 'شخص من الفريق عدّل رقمًا أو مستندًا ماليًا؛ آخر حاول الوصول للمكتب بعد إخلاء الدور؛ المصالح المالية متضاربة بين عدة أطراف.', 'المكتب مرتب بطريقة توحي بالبحث عن ملف بعينه؛ أقوال غير متطابقة عن آخر من رأى الضحية حيًا؛ رسائل داخلية متوترة لا تكشف الجاني مباشرة.', 'أدهم كان يمرر صفقة مشبوهة وكان الضحية سيكشفها، وفريدة شاركته بإخفاء الحسابات والجريمة.', 'جلال طالب بحصته بعدائية؛ نسرين أخفت مسودة عقد قديم؛ بهاء كان سيستفيد من الصفقة دون المشاركة في القتل.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-06', 'قتل', 'الحارس الذي لم يرَ شيئًا', 'يُقتل مدير مخزن داخل منشأة صناعية ليلًا رغم وجود حارس وكاميرا تعطلت قبل الحادثة.', 3, 1, 'حمزة', 'الكاميرا الوحيدة تعطلت قبل الحادثة؛ الجاني يعرف حركة الوردية؛ الضحية كان قد اكتشف مشكلة في المخزن.', 'أحد الموجودين لم يقل الحقيقة كاملة عن موقعه؛ شخص آخر مزق ورقة جرد؛ توتر سابق حول نقص أو خلل في المخزون.', 'باب فرعي استُخدم في وقت قريب من الجريمة؛ إحدى الروايات تغيرت؛ جوهر القضية مرتبط بما كان الضحية يخشاه أن ينكشف.', 'حمزة قتل مدير المخزن بعدما اكتشف الأخير تلاعبًا في المواد والمخزون.', 'ربيع غفا فترة قصيرة؛ إيهاب مزق كشفًا قديمًا يحوي أخطاء تخصه.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-07', 'قتل', 'عشاء لم يكتمل', 'خلال عشاء عائلي لمناقشة الميراث، يتوفى كبير العائلة قبل إعلان قراره الأخير.', 5, 2, 'حازم، فواز', 'المتوفى تناول شيئًا مختلفًا؛ الجميع متوتر قبل إعلان القرار؛ الجريمة مرتبطة بما كان سيُعلن في الليلة نفسها.', 'أحد الحاضرين دخل المطبخ في توقيت غير مبرر؛ شخص آخر كان يبحث عن مستند يخص الميراث؛ أكثر من فرد سيخسر بشدة لو نُفذ القرار الجديد.', 'ترتيب الكؤوس والطاولة لا يتفق مع الروايات؛ أحدهم ناقش الميراث سرًا مع الضحية؛ الأدلة تضع أكثر من شخص داخل دائرة الشك.', 'حازم عرف أنه سيخسر جزءًا أساسيًا من الميراث فتعاون مع فواز الذي خشي كشف تلاعبات مالية سابقة.', 'نجلاء كانت تضغط لتغيير الوصية؛ سامر عليه ديون كبيرة؛ منى كانت تتنصت على حديث خاص.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-08', 'قتل', 'ضحية في الفندق القديم', 'يُعثر على صحفي مقتولًا داخل فندق قديم كان يقيم فيه أثناء تحقيقه في ملف فساد.', 5, 2, 'خالد، رامي', 'الصحفي طلب معلومات إضافية عن أحد النزلاء؛ الفاعل عرف كيف يدخل الغرفة دون ضجة؛ أكثر من شخص لديه ما يخسره لو اكتمل التحقيق.', 'شخص من العاملين أخفى دخول أحد إلى الطابق؛ شخص آخر أخذ أوراقًا من غرفة الصحفي؛ كان الصحفي يثق في أحد الموجودين أكثر من غيره.', 'الغرفة لم تكن في حالة فوضى كاملة؛ حركة المصعد في تلك الليلة متضاربة؛ جزء من أوراق التحقيق مفقود ويورّط أكثر من شخصية.', 'خالد كان محور ملف الفساد، ورامي ساعده في الوصول إلى الغرفة وإخفاء جزء من آثار الجريمة.', 'سمر كانت تخفي مخالفات بالفندق؛ طارق كان غاضبًا من الصحفي؛ ميس أخذت أوراقًا من الغرفة ظنًا أنها مهملة.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-09', 'قتل', 'جريمة في عيادة خاصة', 'يُقتل طبيب معروف داخل عيادته بعد انتهاء العمل دون فوضى كبيرة في المكان.', 3, 1, 'وائل', 'الضحية استقبل أو انتظر شخصًا بعد الإغلاق؛ من دخل يعرف ترتيب العيادة؛ التوتر بين الطبيب وبعض من حوله كان معروفًا.', 'أحد الموجودين أخفى ملفًا أو ورقة؛ شخص آخر سبق أن هدده؛ هناك سبب مهني وسبب شخصي داخل القصة وكلاهما مقنع.', 'استخدام باب داخلي أو مفتاح طوارئ يوسع دائرة الشك؛ من كان آخر من تواصل مع الطبيب غير محسوم؛ شيء اختفى من المكتب قد يرتبط بالانتقام أو الابتزاز.', 'وائل عاد لينتقم من الطبيب بسبب خلاف مالي ومهني قديم كان على وشك التصاعد قانونيًا.', 'حنين أخفت ملف مريض بسبب خطأ إداري؛ عمرو هدده قبل أسبوع لكنه لم يقتله.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('M-10', 'قتل', 'ممر المستشفى', 'في جناح شبه خالٍ بالمستشفى، يُقتل مريض قبل نقله مباشرة.', 5, 2, 'حسام، عاطف', 'المريض توقف في نقطة غير معتادة من الممر؛ أكثر من شخص كان قريبًا من مسار النقل؛ الفاعل يعرف أين ومتى يقل الازدحام.', 'أحد العاملين عدّل سجلًا أو وقتًا متعلقًا بالنقل؛ شخص آخر أخفى أنه كان يبحث عن شيء يخص المريض؛ المريض احتفظ بمعلومة أو مستند يورّط أكثر من طرف.', 'حركة المصعد والسرير لا تتطابق مع الجدول الرسمي؛ الشهود يذكرون وجود شخصين مختلفين قرب السرير؛ شيء مفقود من متعلقات المريض قد يكون سبب الجريمة أو سرًا جانبيًا.', 'حسام خشي انكشاف مستندات مرتبطة بفساد إداري، واستغل عاطف لحظة النقل لتنفيذ الجريمة وخلق ارتباك في السجلات.', 'رنا نسيت تسجيل جرعة؛ ياسر أخطأ في ورقة نقل؛ سلوى كانت تبحث عن متعلق شخصي للمريض.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-01', 'سرقة', 'الخزنة المفتوحة', 'في صباح يوم عمل عادي، تُكتشف خزنة شركة مفتوحة ومبلغ كبير مفقود دون أي آثار كسر.', 5, 2, 'عبير، مؤمن', 'الخزنة لم تُكسر؛ أكثر من شخص يعرف مكانها؛ السرقة استهدفت مبلغًا محددًا فقط.', 'أحد العاملين كان يعرف أن كلمة المرور تغيّرت؛ شخص آخر دخل المكتب بعد ساعات العمل؛ يوجد خلل مالي قديم داخل الشركة.', 'ترتيب الأوراق النقدية يوحي بمعرفة بالنظام الداخلي؛ روايات غير متطابقة عن آخر من أغلق المكتب؛ أكثر من شخص أخفى تحركاته ليلة الحادثة.', 'عبير كانت تغطي عجزًا ماليًا سابقًا، ومؤمن ساعدها عبر الوصول لمعلومة كلمة السر وتسهيل فتح المكتب.', 'هاني كان يحتفظ بمبلغ غير مسجل؛ تيمور دخل المكتب ليلًا لأخذ مفتاح سيارة؛ نور كانت تعرف مكان نسخة ورقية قديمة لكلمة المرور.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-02', 'سرقة', 'سرقة ليلة الزفاف', 'خلال حفل زفاف مزدحم، تختفي حقيبة تحتوي على مجوهرات وهدايا نقدية.', 5, 2, 'جابر، وليد', 'الحقيبة اختفت من غرفة جانبية؛ وقت الاختفاء في ذروة الزحام؛ من أخذها عرف مسبقًا أنها ثمينة.', 'أحد الموجودين كان يعرف مكان المفتاح الاحتياطي؛ شخص آخر شوهد قرب الغرفة أكثر من مرة؛ أزمة مالية كبيرة عند أحد أفراد العائلة.', 'صور الكواليس تظهر حركة غير مفسرة بين الممرات؛ حقيبة مشابهة زادت التشويش؛ توقيت آخر مشاهدة للحقيبة غير متفق عليه.', 'وليد سرق الحقيبة بسبب ديون متراكمة، وجابر سهّل له الوصول والتغطية مستغلًا مسؤوليته عن القاعة.', 'شيرين أخفت جزءًا من الذهب؛ منة دخلت الغرفة للبحث عن هدية خاصة؛ طه تحرك بحرية في الكواليس لالتقاط صور إضافية.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-03', 'سرقة', 'مستودع بلا آثار', 'تختفي شحنة أجهزة إلكترونية من مستودع مغلق دون أي كسر ظاهر.', 3, 1, 'عز', 'باب التحميل فُتح لفترة قصيرة جدًا؛ من سرق الشحنة يعرف نوع البضاعة ومكانها؛ لا توجد فوضى تدل على بحث عشوائي.', 'أحد العاملين غيّر موعد تسليم في النظام؛ شخص آخر تأخر في الإبلاغ عن خلل بالبوابة؛ الشحنة المفقودة كانت ضمن شحنة أكبر.', 'مركبة دخلت نطاق المستودع في توقيت غير واضح الغرض؛ أقوال العاملين حول آخر من راجع الحمولة لا تتطابق؛ أحدهم أخفى معلومة عن يوم سابق.', 'عز عدّل موعد الشحنة واستخدم مسار تحميل سريعًا لاستخراج الأجهزة وبيعها عبر طرف خارجي.', 'سامي أخفى نقصًا قديمًا في الجرد؛ رائد كان يعلم بخلل في حساس الباب ولم يبلغ فورًا.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-04', 'سرقة', 'الحقيبة التي لم تصل', 'حقيبة تحتوي على أموال ومستندات مهمة تختفي أثناء انتقالها بين فرعين لشركة.', 3, 1, 'شادي', 'الرحلة استغرقت الوقت المعتاد تقريبًا؛ أكثر من شخص تعامل مع الحقيبة؛ من أخذها عرف أنها ليست مجرد مستندات.', 'اختلاف في وصف شكل الحقيبة ولحظة تحميلها؛ أحد الأطراف لم يذكر توقفًا قصيرًا أثناء الطريق؛ شخص آخر لم يعدّ المحتويات بدقة قبل التسليم.', 'كاميرا طريق تُظهر فتح الصندوق الخلفي؛ اتصال هاتفي جرى أثناء الرحلة؛ رواية أحدهم تخفي فترة زمنية حرجة.', 'شادي استغل توقفًا قصيرًا وسلّم الحقيبة لطرف خارجي قبل الوصول.', 'منير لم يراجع كامل المحتوى قبل التحرك؛ فاطمة أخفت أنها تأخرت في الحضور.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-05', 'سرقة', 'سرقة في النادي', 'تختفي عدة هواتف ومبالغ مالية من غرف تبديل الملابس في نادٍ خاص.', 5, 2, 'لؤي، آسر', 'السرقة حدثت أثناء انتقال الجميع إلى الملعب؛ أكثر من شخص كان لديه سبب لدخول الغرفة؛ الأغراض المسروقة من عدة خزائن.', 'أحد الموظفين استخدم مفتاحًا احتياطيًا؛ أحد اللاعبين كان يعاني أزمة مالية؛ شخص ثالث أخفى أنه عاد للغرفة بعد بدء التدريب.', 'الحقائب فُتحت بطريقة يعرفها أكثر من شخص؛ شهادة الموجودين عن آخر شخص في الممر غير مستقرة؛ توجد إشارة إلى اتفاق سابق بين شخصين.', 'لؤي خلق تشتيتًا بنقل الجميع سريعًا إلى الملعب، وآسر استغل الفرصة وسرق الأغراض من داخل الغرفة.', 'رشا أعطت مفتاحًا احتياطيًا سابقًا دون تسجيل؛ كريم كان مديونًا؛ هنا عادت للغرفة لأخذ شيء نسيته.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-06', 'سرقة', 'المكتب المغلق', 'تختفي شيكات موقعة وبيانات حساسة من مكتب المدير المالي رغم أنه ظل مغلقًا طوال اليوم.', 5, 2, 'يونس، شريف', 'العناصر المسروقة محددة بدقة؛ لا أثر كسر؛ أكثر من شخص لديه سبب للدخول إلى المكتب أو معرفة ما بداخله.', 'أحدهم وصل إلى القفل الإلكتروني أو النظام؛ شخص آخر كان يتابع ملف مشتريات حساسًا؛ توجد نسخ ورقية أو رقمية خارج الإجراء الطبيعي.', 'تم سحب ملف رقمي في توقيت يضع أكثر من موظف تحت الشبهة؛ هناك دخول بعد الدوام؛ بعض الشيكات المفقودة مرتبطة بمسار مالي يورّط أكثر من إدارة.', 'يونس سرق البيانات والشيكات لتغطية صفقة مشتريات فاسدة، وشريف سهّل له الوصول الرقمي وفتح المسار.', 'ندى أخفت ورقة موقعة كانت قد سحبتها للتصوير؛ أيمن احتفظ بنسخة خارجية لبعض الملفات؛ مها استعارت المفتاح سابقًا.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-07', 'سرقة', 'الدرج الفارغ', 'بعد ليلة جرد طويلة، يختفي الإيراد اليومي من درج المحاسبة.', 3, 1, 'فادي', 'الدرج أُغلق بشكل طبيعي تقريبًا؛ كل من شارك في الجرد لمس الدرج؛ الفاعل فهم جيدًا نظام العد والتسليم.', 'أحد الموجودين أعاد فتح الدرج بعد الجرد؛ شخص آخر غيّر ترتيب المناوبة شفهيًا؛ خطأ في كشف التسليم يجعل لحظة الاختفاء غير محسومة.', 'بعض الأوراق النقدية من نفس الفئة ظهرت في مكان يثير الشبهة؛ كل طرف يحمّل الآخر مسؤولية آخر لمسة؛ أحدهم أخفى أمرًا سابقًا غير مرتبط مباشرة بالسرقة.', 'فادي أخفى المبلغ قبل العد النهائي ثم أعاد ترتيب الدرج ليبدو كل شيء طبيعيًا.', 'سمر بدلت المناوبة دون تسجيل؛ يوسف أخطأ في جزء من كشوف التسليم.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-08', 'سرقة', 'هاتف المدير', 'يختفي هاتف مدير مشروع وفيه عقود وصور حساسة، ثم تصل رسالة تهديد غير مباشرة.', 5, 2, 'هشام، مراد', 'الهاتف اختفى من داخل غرفة الاجتماع؛ من أخذه كان يعرف أن ما بداخله أهم من قيمة الهاتف؛ أكثر من شخص لديه سبب للوصول للملفات أو الصور.', 'إحدى الكاميرات في الممر لم تسجل طبيعيًا؛ شخص من الحاضرين كان يخشى صورًا أو عقودًا تتعلق به؛ أحد الموجودين أمسك الهاتف قبل اختفائه بدقائق.', 'شريحة الهاتف حاولت الاتصال لاحقًا من منطقة قريبة؛ رسالة التهديد صيغت بلغة يعرفها أكثر من شخص؛ كل لاعب لديه سبب لإخفاء تفصيلة صغيرة عن الاجتماع.', 'هشام أراد الوصول إلى صور وعقود قد تضره، ومراد سرق الهاتف وسهّل إخفاء أثره واستُخدم لاحقًا للضغط غير المباشر.', 'نسر كان يصور بعض المستندات لنفسه؛ لينا أمسكت الهاتف لترتيب رسالة عاجلة؛ بهاء كان يخفي محتوى شخصيًا.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-09', 'سرقة', 'السرقة أثناء انقطاع الكهرباء', 'أثناء انقطاع كهربائي قصير في مبنى إداري، تختفي قطعة إلكترونية ثمينة من المختبر.', 3, 1, 'طارق', 'القطعة نُزعت بشكل احترافي؛ انقطاع الكهرباء منح فرصة لعدة أشخاص؛ المسروق ليس الأكبر حجمًا بل الأعلى قيمة لمن يعرفه.', 'أحد اللاعبين كان يعرف موعد الانقطاع المتوقع بدقة؛ شخص آخر سبق أن طلب استخدام القطعة؛ توتر سابق حول حفظ المعدات.', 'أداة صغيرة استُخدمت في النزع ويمكن لأكثر من شخص الوصول لمثلها؛ التسلسل الزمني داخل المختبر قابل لأكثر من تفسير؛ أحدهم أخفى شيئًا في نفس اليوم.', 'طارق استغل علمه بتوقيت الانقطاع ونزع القطعة بسرعة لبيعها لطرف خارجي.', 'خالد أخفى تأخره في الجرد؛ نوران طلبت استعارة القطعة دون موافقة مكتوبة.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('T-10', 'سرقة', 'متجر الهدايا', 'تعرض متجر صغير للتخريب بينما اختفت منه قطع محددة فقط.', 5, 2, 'مروان، يحيى', 'القطع المسروقة ليست الأغلى كلها لكنها من خط إنتاج واحد؛ التخريب قد يكون تمويهًا أو رسالة شخصية؛ الفاعل يعرف التخطيط الداخلي.', 'أحد اللاعبين يعرف المخزن الخلفي جيدًا؛ شخص آخر له علاقة بسوق بيع مشابهة؛ موظفة أخفت خطأ سابقًا في الجرد.', 'باب الخدمة الخلفي فُتح في وقت غير معتاد؛ إشارات إلى تنسيق بين شخصين دون حسم طبيعته؛ اختلاف حول ما إذا كان التخريب سبق السرقة أم العكس.', 'مروان نفذ التخريب كنوع من الانتقام، ويحيى استغل ذلك ليسرق قطعًا أصلية لصالح بيع موازٍ.', 'شهد أخفت خطأ في الجرد؛ لمى احتفظت بقطعة داخل حقيبتها لتجربتها؛ هبة أخفت خلافًا قديمًا مع مروان.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-01', 'خطف', 'الطفلة عند البوابة', 'بعد انتهاء اليوم الدراسي، تختفي طفلة من أمام بوابة المدرسة دون صراخ أو مقاومة.', 5, 2, 'حسام، رامي', 'الطفلة خرجت بهدوء مع شخص مألوف؛ أكثر من شخص يعرف اسمها وطريقة استدعائها؛ لا استخدام واضح للقوة.', 'أحد الموجودين أخفى أنه كان قريبًا من البوابة؛ شخص آخر يمر بأزمة مالية أو عائلية؛ الطفلة كانت تنتظر شخصًا سيأخذها اليوم.', 'تسجيل شارع جانبي يظهر سيارة قريبة من المدرسة؛ روايات متضاربة عن آخر من تحدث مع الطفلة؛ أكثر من شخص لديه سبب لإخفاء تحركاته بعد الدوام.', 'حسام دبّر الخطف للضغط على والد الطفلة ماليًا، ورامي ساعده مستخدمًا ثقة الطفلة به كسائق معروف.', 'أميرة وبخت الطفلة في اليوم نفسه؛ داليا تركت البوابة لدقائق؛ شريف كان يراقب المكان لمقابلة والد الطفلة.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-02', 'خطف', 'الخطف الصامت', 'يختفي شاب بعد خروجه من العمل دون أي استغاثة أو رسالة.', 3, 1, 'هيثم', 'الضحية لم يختفِ في مكان عشوائي؛ يبدو أنه غيّر مساره بإرادته للحظات؛ الفاعل استخدم سببًا مقنعًا مرتبطًا بالعمل أو العائلة.', 'أحد المقربين كذب بشأن آخر تواصل معه؛ شخص آخر كان لديه خلاف مهني؛ الضحية كان يخفي شيئًا عن أسرته وعن زملائه.', 'سيارة شوهدت قرب مكان الاختفاء؛ شخص من الدائرة القريبة حذف أو عدّل معلومة تخص تحركات ذلك اليوم؛ كل لاعب لديه سبب لإخفاء جزء من علاقته بالضحية.', 'هيثم استدرج الضحية بحجة عمل عاجلة ثم خطفه بسبب نزاع مالي وخوف من انكشاف تلاعب داخل الشركة.', 'زياد كان ينافس الضحية على ترقية؛ تامر أخفى خلافًا عائليًا قديمًا.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-03', 'خطف', 'رهينة الشركة', 'يختفي موظف مالي قبل يوم واحد من مراجعة حسابات حساسة داخل الشركة.', 5, 2, 'جابر، حمدي', 'الضحية اختفى بعد يوم متوتر في العمل وكان يحمل ملفات لا يجب أن تخرج؛ أكثر من شخص كان يعرف أنه يعمل على مراجعة حساسة؛ لا توجد مؤشرات على هروب طوعي.', 'أحد العاملين أخفى اجتماعًا أخيرًا معه؛ شخص آخر تلاعب بجزء من سجل الدخول والخروج؛ الضحية كان يثق في شخص من داخل الشركة.', 'بطاقة الضحية استُخدمت لاحقًا في مكان غير متوقع؛ بعض المستندات التي كان يحملها اختفت بينما بقيت أخرى؛ أكثر من شخصية لديها مصلحة في ألا تكتمل المراجعة.', 'جابر دبّر الخطف لمنع الموظف من تسليم أدلة فساد مالي، وحمدي ساعده عبر التحكم في السجلات وتأمين مكان الاحتجاز.', 'منى نسخت بعض الملفات لنفسها؛ سيف كان مدينًا للضحية؛ ندى أخفت بلاغ تهديد قديم.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-04', 'خطف', 'عودة السيارة بلا صاحبها', 'تُعثر على سيارة رجل أعمال متوقفة في مكان هادئ ومحركها لا يزال دافئًا، لكن صاحبها اختفى.', 3, 1, 'لؤي', 'السيارة لم تُسرق؛ يبدو أن الضحية توقف لسبب محدد؛ أكثر من شخص يعرف جدول تحركاته.', 'أحد المقربين أخفى مكالمة أو موعدًا؛ شخص آخر لم يذكر الحقيقة كاملة عن آخر مرة رآه فيها؛ كان الضحية على وشك اتخاذ قرار تجاري يضر بأحد شركائه أو معاونيه.', 'أثر ورقة أو عنوان مرتبط بمكان يعرفه أكثر من طرف؛ ما داخل السيارة يشير إلى أن اللقاء لم يبدأ بعنف مباشر؛ لكل لاعب رواية منطقية عن سبب معرفته بالمكان أو الوقت.', 'لؤي استدرج شريكه إلى اللقاء ثم اختطفه للضغط عليه في نزاع استثماري كبير.', 'صبري كذب بشأن موعد آخر توصيل؛ مايا حذفت رسالة شخصية من هاتف الضحية بعد اختفائه.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-05', 'خطف', 'الخطف مقابل الصمت', 'تختفي صحفية كانت تعمل على ملف فساد محلي، وتصل رسالة تطالب بإغلاق التحقيق.', 5, 2, 'أشرف، فهد', 'آخر تحركات الصحفية كانت مرتبطة بمصدر أو مكان حساس؛ أكثر من شخص كان يعلم أنها اقتربت من معلومة خطيرة؛ لا توجد مؤشرات على مقاومة في نقطة الاختفاء.', 'أحد المقربين أخفى جزءًا من المادة الصحفية؛ شخص آخر أنكر لقاءه بها في اليوم نفسه؛ الصحفية كانت تشك في أكثر من طرف.', 'إيصال أو أثر تحرك يربط أحد اللاعبين بمكان ناءٍ؛ الهاتف توقف في نطاق منطقة يستخدمها أكثر من شخص؛ بعض الأوراق المفقودة من ملف التحقيق كانت ستورّط أكثر من اسم.', 'أشرف أمر بخطفها لمنع نشر ملف الفساد، وفهد نفّذ الاستدراج والنقل بحكم قربه المعتاد منها كسائق.', 'كريم أخفى بطاقة ذاكرة؛ دانا كانت تحاول النشر وحدها؛ رانيا كانت تتجادل معها حول معلومة حساسة.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-06', 'خطف', 'الطفل والرسمة', 'يختفي طفل من داخل نادٍ اجتماعي، ويُعثر على ورقة تحمل رسمة غريبة بالقرب من المكان.', 3, 1, 'مؤيد', 'الطفل شوهد آخر مرة في منطقة يعتاد التحرك فيها؛ الرسمة قد تكون مفتاحًا مهمًا أو أثرًا جانبيًا؛ من نفذ العملية يعرف روتين النادي الداخلي.', 'أحد الموجودين كان قريبًا من الطفل قبل دقائق؛ شخص آخر يعرف معنى الرمز أو شاهده سابقًا؛ هناك تهديد أو توتر سابق يخص العائلة.', 'باب جانبي فُتح في توقيت مهم؛ بعض التفاصيل حول الرسمة تدفع الشك نحو شخص بينما باقي المعطيات تفتح الشك على آخر؛ الأب نفسه يخفي شيئًا يجعل القضية تبدو عائلية.', 'مؤيد استغل عمله داخل منطقة الألعاب وخطف الطفل لصالح طرف خارجي يعرف الأب.', 'باسل أخفى تهديدًا قديمًا؛ نغم كانت آخر من تحدث مع الطفل قبل دقائق.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-07', 'خطف', 'رحلة لم تكتمل', 'أثناء توقف رحلة جماعية قصيرة في محطة استراحة، يختفي أحد الركاب.', 5, 2, 'علاء، نادر', 'الحافلة تأخرت بضع دقائق أكثر من المعتاد؛ الضحية خرج مع شخص أو قابل شخصًا خلال التوقف؛ من دبّر الخطف استغل ازدحامًا قصيرًا.', 'أحد المشاركين كذب بشأن موقعه أثناء الاستراحة؛ شخص آخر كان في خلاف حاد مع الضحية؛ الضحية تلقى رسالة أو تنبيهًا جعله يبتعد عن المجموعة.', 'كاميرا المحطة تُظهر انتقالًا في الخلفية دون وضوح كامل؛ هناك توقيت مفقود في رواية السائق مع وجود ثغرات عند غيره؛ أكثر من شخصية كانت تعرف مسبقًا أن الضحية سيشارك في الرحلة.', 'نادر استدرج الضحية بعيدًا، وعلاء ساعد في خلق التأخير وتسهيل تسليمه إلى السيارة التي نفذت الخطف.', 'لمياء كانت تتشاجر معه؛ فارس كان مدينًا له؛ جنى لم تسجل المشاركين بدقة عند التوقف.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-08', 'خطف', 'المختفية من الحفل', 'تختفي فتاة من حفل عيد ميلادها دون صراخ أو مقاومة.', 5, 2, 'يامن، رامي', 'خرجت الفتاة من القاعة بنفسها؛ أكثر من شخص كان يعلم أنها متوترة من الحضور؛ لا يوجد دليل على اختطاف عنيف من داخل الحفل.', 'أحد اللاعبين تحرك في الممرات الخلفية؛ شخص آخر كان يحاول التواصل معها بشكل متكرر قبل الاختفاء؛ المختفية كانت تخفي سرًا قد يجعلها تغادر طوعًا للحظة ثم تقع في الفخ.', 'رسالة خرجت من هاتفها بعد اختفائها؛ كاميرا جانبية تعطلت أو لم تغط الزاوية المطلوبة؛ أقوال الموجودين عن آخر من رأى وجهها مباشرة مختلفة.', 'يامن استدرجها خارج الحفل، ورامي ساعده في تمريرها من الممرات الخلفية بعيدًا عن الانتباه.', 'هبة كانت تعلم أنها تنوي المغادرة مبكرًا؛ ليث دخل في شجار معها؛ تمارا كانت تخفي سرًا مهنيًا تخشى أن تفضحه المختفية.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-09', 'خطف', 'شاهد القضية', 'قبل الإدلاء بشهادته بساعات، يختفي شاهد رئيسي في قضية حساسة.', 3, 1, 'جاد', 'مكان الحماية لم يكن معروفًا لعامة الناس؛ الشاهد أُخذ بعد لحظة استدراج أو ثقة؛ من نفذ الخطف يعرف توقيت انتقاله بدقة.', 'أحد المقربين أخفى محادثة أخيرة معه؛ شخص آخر لم يذكر الحقيقة كاملة عن ترتيبات الحماية؛ هناك مصلحة عند أكثر من طرف في منعه من الوصول للمحكمة.', 'سيارة غير رسمية ظهرت قرب الموقع؛ بعض سجلات الحركة تم تعديلها أو تعطيلها؛ العلاقة الشخصية بين الشاهد وأحد من حوله تجعل الشك يتحرك أكثر من مرة.', 'جاد، المكلف بالحماية، باع موقع الشاهد وساهم في اختطافه مقابل منفعة مالية.', 'سعيد أخفى مذكرة قانونية حساسة؛ وائل حاول فعلًا إقناع الشاهد بعدم الحضور.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('K-10', 'خطف', 'الممر الخلفي', 'يختفي مدير مطعم معروف بعد خروجه دقائق إلى الممر الخلفي للمبنى.', 5, 2, 'ماهر، أنس', 'الاختفاء حدث في نقطة لا تراقبها الكاميرات جيدًا؛ أكثر من شخص له سبب للتواجد في الممر الخلفي؛ يبدو أن المدير خرج ليلتقي شخصًا أو ليتحقق من أمر مستعجل.', 'أحد العاملين أخفى تحركًا غير معتاد قرب باب الخدمة؛ شخص آخر كان في نزاع مالي أو إداري مع المدير؛ المختفي كان يحتفظ بمعلومة تخص التوريد أو النقدية أو الشراكة.', 'تسجيل شارع خلفي يُظهر حركة مركبة وتوقفًا قصيرًا؛ الأقوال حول آخر من تحدث مع المدير قبل خروجه متضاربة؛ كل لاعب تقريبًا لديه سبب لإخفاء شيء عن تلك الليلة.', 'ماهر خطف المدير للضغط عليه بسبب عقد توريد فاسد كان على وشك الانكشاف، وأنس ساعده في النقل والمراقبة.', 'شادي تشاجر معه حول جودة التوريد؛ رولا أخفت نقصًا في النقدية؛ بشرى كانت تفكر في إنهاء الشراكة.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-01', 'ابتزاز', 'الرسالة الأولى', 'يتلقى مدير مدرسة رسالة مجهولة تهدده بنشر صور قديمة إذا لم يدفع مبلغًا كبيرًا.', 5, 2, 'أمجد، إياد', 'الصور ليست متاحة للعامة؛ الابتزاز استهدف نقطة حساسة في الماضي؛ أكثر من شخص لديه سبب للغضب من المدير أو لإضعافه.', 'أحد العاملين دخل إلى ملفات قديمة أو نظام أرشفة؛ شخص آخر كان يعرف بوجود الصور قبل الرسالة؛ يوجد طرف من خارج المدرسة لديه دافع أيضًا.', 'الرسالة أُرسلت من بيئة تقنية مألوفة لأكثر من شخص؛ بعض التفاصيل في الصياغة تشبه أسلوب شخص معروف لكن يمكن تقليدها؛ كل طرف أخفى شيئًا عن علاقته السابقة بالمدير.', 'أمجد أراد الانتقام من المدير بسبب خلاف مهني قديم، بينما إياد وفر له الوصول للأرشيف والطريقة التقنية للإرسال.', 'سوسن كانت تطمح للمنصب؛ ليلى فتحت الأرشيف لأغراض تنظيمية؛ حسان كان يجهز شكوى قوية ضد الإدارة.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-02', 'ابتزاز', 'ابتزاز الشريك', 'يتلقى شريك تجاري رسائل تحتوي على تفاصيل دقيقة عن تحويلات مالية سرية.', 3, 1, 'ناصر', 'الرسائل تحتوي أرقامًا دقيقة لا يمكن تخمينها؛ المبتز يريد إبقاء الضحية تحت السيطرة؛ أكثر من شخص مرّ على هذه الملفات أو سمع عنها.', 'أحد الموظفين دخل النظام خارج الدوام؛ شخص آخر كان يطبع أوراقًا مالية حساسة؛ الضحية نفسه أخفى بعض التحويلات عن شركائه.', 'بعض المستندات المستخدمة في الرسائل خرجت من الجهاز الداخلي؛ أسلوب الكتابة يوحي بشخص مطلع وهادئ؛ هناك دافع انتقام ودافع مالي ودافع حماية للنفس.', 'ناصر استغل معرفته الكاملة بالحسابات والملفات لابتزاز الشريك والحصول على المال قبل انكشاف اختلاسه السابق.', 'باسمة كانت تطبع ملفات خارج الإجراءات؛ رائد أخفى تحويلًا شخصيًا غير معلن.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-03', 'ابتزاز', 'الصوت المسجل', 'يتلقى سياسي محلي تسجيلًا صوتيًا محرجًا مع تهديد بالنشر.', 5, 2, 'شوقي، حسني', 'التسجيل من لقاء محدود الحضور أو الوصول إليه؛ المبتز يعرف قيمة التوقيت السياسي للنشر؛ أكثر من شخص يربح لو تضررت سمعة السياسي.', 'أحد الأشخاص كان قادرًا على الوصول للمكان أو الأجهزة؛ شخص آخر حاول معرفة تفاصيل اللقاء بعد حدوثه؛ الصحافة والمنافسون والفريق الداخلي كلهم لديهم دوافع مختلفة.', 'ظهرت مؤشرات على وجود جهاز تسجيل؛ توقيت الرسالة ينسجم مع مصلحة طرف سياسي لكن الصياغة ليست حاسمة؛ بعض التصرفات اللاحقة تبدو أقرب إلى التستر منها إلى الجريمة نفسها.', 'حسني زرع وسيلة التسجيل مستغلًا قربه من المكان، وشوقي استخدم المادة لابتزاز خصمه سياسيًا وماليًا.', 'آدم كان يجهز حملة إعلامية مضادة؛ سهير سربت جدول لقاءات سابقًا؛ لمياء كانت تبحث عن سبق صحفي.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-04', 'ابتزاز', 'الحساب المجهول', 'تبدأ منشورات تلميحية بالظهور من حساب مجهول تستهدف طبيبة معروفة.', 5, 2, 'عماد، فادي', 'المنشورات تحتوي معلومات وصورًا من داخل العيادة أو من ملفاتها؛ الحساب يريد الضغط لا التشهير فقط؛ أكثر من شخص له سبب لعداوة الطبيبة أو إحراجها.', 'أحد العاملين لديه وصول للكاميرات أو الأجهزة؛ شخص آخر كان يطالب الطبيبة بشيء رفضته من قبل؛ المواد قد تكون خرجت من النظام أو من هاتف أو من حديث مسموع.', 'الحساب يستخدم أسلوبًا ومصطلحات يعرفها أكثر من لاعب؛ صور من داخل العيادة قد تعني اختراقًا أو تصويرًا داخليًا قديمًا؛ أكثر من لاعب أخفى أنه كان داخل العيادة في وقت حساس.', 'عماد أراد الضغط على الطبيبة لتحقيق مصلحة خاصة، وفادي زوده بالمواد والوصول التقني.', 'مهند أخفى خطأ مهنيًا بسيطًا؛ سارة كانت تغار مهنيًا؛ نجلاء احتفظت بصور من ملفات إدارية لأغراض العمل.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-05', 'ابتزاز', 'السر العائلي', 'رجل ثري يتلقى تهديدًا بنشر سر قديم يهدد مكانة العائلة.', 3, 1, 'مؤنس', 'السر قديم جدًا ويعرفه عدد محدود؛ الرسائل تتحرك بحذر ومعرفة بنقاط ضعف العائلة؛ أكثر من شخص في البيت كان يفتش في أوراق قديمة أو غرف مغلقة.', 'أحد المقربين كان حاضرًا وقت الحادثة الأصلية؛ شخص آخر لديه مصلحة في تغيير صورة الأب؛ بعض الأدراج أو المستندات القديمة فُتحت من جديد.', 'وسيلة الاتصال المستخدمة تبدو بسيطة جدًا؛ بعض العبارات في التهديد تشبه أسلوب شخص من داخل البيت؛ كل طرف لديه سبب مختلف لإخفاء علاقته بالماضي.', 'مؤنس احتفظ بمعرفة السر سنوات طويلة ثم استخدمه لابتزاز الرجل الثري والحصول على المال.', 'رانيا كانت تفتش في الأوراق القديمة؛ عزت أخفى مستندًا يتعلق بالميراث.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-06', 'ابتزاز', 'صور الحفل', 'بعد حفل خاص، يتلقى أحد الحضور صورة من زاوية لم يلاحظها أحد مع طلب دفع سريع.', 5, 2, 'زيد، مروان', 'الصورة ليست من الكاميرات الرسمية الظاهرة؛ المبتز اختار لقطة ذات دلالة عالية؛ أكثر من شخص من طاقم الحفل قادر على التواجد في الزوايا الخلفية.', 'أحد العاملين ثبت جهازًا أو معدات في مكان غير معتاد؛ شخص آخر طلب نسخًا خامًا أو احتفظ بها قبل التسليم؛ بعض الضيوف لديهم ما يخشون خروجه من صور تلك الليلة.', 'الملف الأصلي أو مسار التخزين يشير إلى جهة تقنية لكن ليست بالضرورة الجهة المبتزة نفسها؛ هناك أثر لتنسيق بين شخصين؛ كل رواية عن من كان يتحكم بالمواد الخام تحمل فجوة صغيرة.', 'مروان جهّز وسيلة تصوير جانبية، وزيد احتفظ بالمواد واستخدمها في الابتزاز بعد اختيار اللقطة المناسبة.', 'طلال أخفى هوية بعض الضيوف؛ فرح غيرت ترتيب الكاميرات والديكور؛ نهى كانت تريد حذف صور أخرى لا علاقة لها بالابتزاز.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-07', 'ابتزاز', 'ملفات الموظف', 'تتلقى مديرة شركة لقطات من ملفات سرية على جهازها الشخصي مع طلبات متزايدة.', 5, 2, 'وائل، حازم', 'الملفات خرجت من الجهاز الشخصي للمديرة؛ المبتز يعرف ترتيب الملفات وأهميتها؛ أكثر من شخص لديه دافع للضغط على الإدارة الحالية.', 'أحد العاملين يملك القدرة على الوصول التقني للأجهزة؛ شخص آخر لديه عداء مباشر مع الإدارة؛ بعض التحركات داخل المكتب تبدو بريئة ظاهريًا لكنها تفتح الشك.', 'أثر البرنامج أو طريقة النسخ يضع الشبهة على مختص تقني لكن قد يكون تمويهًا؛ الحساب المستلم لا يرتبط مباشرة بالفاعلين؛ من حول المديرة يخفون أمورًا صغيرة تجعلهم أكثر شبهًا.', 'وائل أراد الانتقام والضغط للحصول على مكاسب، وحازم زوده بالوصول للأجهزة والملفات.', 'رفيف كانت تفتح جهاز المديرة أحيانًا بتكليف شفهي؛ سلمى أخفت ملف فصل وائل؛ بهجت دخل المكتب خارج وقته لتنظيف عاجل.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-08', 'ابتزاز', 'المعلم الجديد', 'يتعرض معلم جديد لابتزاز بحادثة قديمة من مدرسته السابقة.', 3, 1, 'وسام', 'المعلومات المستخدمة في الابتزاز ليست عامة ويمكن أن تكون خرجت من ملف رسمي أو من معرفة شخصية؛ المبتز يريد إضعاف المعلم لا تدميره مباشرة؛ أكثر من شخص يعرف جزءًا من ماضيه.', 'أحد العاملين اطلع على ملف التوظيف دون إذن واضح؛ شخص آخر كان يتواصل مع جهة من المدرسة السابقة؛ هناك منافسة مهنية واضحة داخل المدرسة.', 'طريقة إرسال الرسائل بسيطة؛ بعض التعبيرات المستخدمة تبدو من شخص قريب داخل البيئة التعليمية؛ أحد اللاعبين كان يحاول حماية المعلم فعلًا لكن تصرفاته بدت مشبوهة.', 'وسام استغل معلومات حصل عليها من تواصل سابق مع جهة من مدرسة المعلم القديمة وابتزه بدافع الغيرة المهنية.', 'طارق أخفى شكوى قديمة عن المعلم الجديد؛ علاء فتح ملف التوظيف دون تصريح كامل.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-09', 'ابتزاز', 'فيديو المصعد', 'يتلقى موظف حكومي تهديدًا بنشر فيديو له داخل المبنى إذا لم يمرر معاملة مشبوهة.', 5, 2, 'فراس، قاسم', 'الفيديو من كاميرا داخلية يصعب الوصول إليها؛ الابتزاز مرتبط بتمرير معاملة؛ أكثر من شخص في المبنى يعرف حساسية الفيديو.', 'أحد العاملين قادر على نسخ أو الوصول إلى التسجيلات؛ شخص آخر كان يضغط أصلًا لإنجاز معاملة؛ أكثر من طرف أخفى معرفته بالفيديو قبل البلاغ الرسمي.', 'نسخة الفيديو خرجت من بيئة العمل لكن يمكن أن تكون عبر تسريب مباشر أو تصوير غير مباشر؛ الحساب المستخدم لا يشير بوضوح إلى مصدر واحد؛ الدافع قد يكون ماليًا أو إداريًا أو انتقاميًا.', 'قاسم نسخ الفيديو من النظام الداخلي، وفراس استخدمه للضغط على الموظف وتمرير معاملة مشبوهة.', 'نزار كان على خلاف وظيفي مع الضحية؛ سعاد أخفت ملف معاملة مشابهة؛ هاجر كانت تعلم بوجود الفيديو قبل الإعلان.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('B-10', 'ابتزاز', 'الابتزاز المزدوج', 'يكتشف أحد الضحايا أن المبتز يضغط في الوقت نفسه على شخص آخر من نفس الدائرة.', 5, 2, 'باسل، مازن', 'الرسائل للضحيتين تحمل نفس الأسلوب العام مع تفاصيل مختلفة؛ المبتز يعرف ملفات حساسة تخص أكثر من شخص؛ هذا النوع من الضغط يحتاج وصولًا واسعًا أو شراكة.', 'أحد اللاعبين لديه وصول منظم لكثير من البيانات؛ شخص آخر لديه مصلحة تجارية في إضعاف الطرفين؛ بعض المستندات المستخدمة كانت معروفة داخليًا لكن ليس بهذه الدقة.', 'طريقة جمع المعلومات تبدو تقنية ومنهجية، بينما التفاوض يبدو شخصيًا وتجاريًا؛ ظهرت إشارات إلى تنسيق خارجي؛ كل من في المجموعة أخفى معلومة صغيرة عن علاقته بالمستندات أو بالضحايا.', 'باسل جمع المعلومات من خلال وصوله إلى البيانات، ومازن استخدمها في الابتزاز لتحقيق ضغط تجاري ومكاسب مباشرة.', 'جلال يخفي اتفاقًا جانبيًا؛ يارا عدلت كشف حساب سابقًا؛ شهد قرأت بعض الرسائل أو الملفات دون إذن.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-01', 'اختفاء دليل', 'ملف القضية المفقود', 'قبل جلسة قانونية مهمة بساعات، تختفي ورقة أساسية من ملف قضية داخل مكتب محاماة.', 5, 2, 'نادر، عارف', 'الورقة المفقودة كانت وسط ملف كامل؛ أكثر من شخص تعامل مع الملف؛ اختفاء الورقة قد يفيد طرفًا قانونيًا أو يخفي فضيحة داخلية.', 'أحد العاملين دخل غرفة الحفظ بعد انتهاء الوقت المعتاد؛ شخص آخر حاول مراجعة الملف على انفراد؛ يوجد توتر قديم بين المكتب والموكلة حول جزء من المستندات.', 'آثار الترتيب داخل الملف توحي ببحث بعناية؛ سجل الحركة الداخلي يضع أكثر من شخص قرب مكان الحفظ؛ كل طرف تقريبًا لديه سبب لإخفاء شيء يخص الملف.', 'نادر أمر بإخفاء الورقة لأنها كانت ستُضعف موقفه القانوني وتكشف تقصيرًا منه، وعارف ساعده عبر الوصول إلى غرفة الحفظ وسحب المستند.', 'جود كانت تنسخ الملف سرًا؛ منال أخفت مستندًا جانبيًا محرجًا؛ سليم خلط بين ملفات مالية تخص القضية وأخرى مختلفة.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-02', 'اختفاء دليل', 'الفلاش ميموري', 'وحدة تخزين تحتوي على تسجيل كاميرا مهم تختفي بعد أن شاهدها أكثر من شخص.', 3, 1, 'خالد', 'الفلاش لم يكن ضائعًا منذ البداية بل اختفى بعد تداوله؛ التسجيل مهم لكنه قد يدين أكثر من طرف؛ كل من تعامل معه لديه سبب ليخفي خطأً أو تقصيرًا.', 'أحد اللاعبين أخفى أين وضع الفلاش آخر مرة؛ شخص آخر فتح التسجيل مرة إضافية؛ الروايات متضاربة حول وجود نسخة احتياطية.', 'أثر رقمي أو نسخة مؤقتة وُجدت على جهاز داخلي؛ التسلسل الزمني يسمح باتهام أكثر من شخص؛ أحد اللاعبين يتصرف وكأنه يخشى ما في الفيديو وآخر يخشى فقط اتهامه بالتقصير.', 'خالد أخفى الفلاش لأنه كان يحمي شخصًا يعرفه ويدرك أن التسجيل سيورطه مباشرة أو يفضح صلته بالواقعة.', 'بسمة فتحت الفلاش بنفسها قبل تسليمه؛ أنور أخطأ في تسمية النسخة الرقمية.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-03', 'اختفاء دليل', 'تقرير المختبر', 'تقرير معمل حساس يختفي قبل تسليمه، بينما يمكن لنتيجته أن تبرئ شخصًا أو تدين آخر.', 5, 2, 'سامر، وليد', 'التقرير المفقود هو النتيجة الوحيدة التي لم تُؤرشف بشكل مكتمل؛ أكثر من شخص كان يعرف أهميته؛ اختفاؤه قد يفيد طرفًا خارجيًا أو يحمي سمعة داخلية.', 'أحد اللاعبين تعامل مع الطباعة أو الإرسال خارج الروتين؛ شخص آخر طلب تأجيل التسليم دون سبب مقنع؛ بيانات العينة نفسها كانت محل ارتباك سابق.', 'آثار تمزيق أو إعادة طباعة وُجدت لكنها لا تحسم الهدف؛ السجل الداخلي يُظهر نشاطًا من أكثر من مستخدم؛ لكل لاعب دافع جانبي لإخفاء جزء من الحقيقة.', 'سامر أخفى التقرير لأنه كان يحمي عميلًا ذا نفوذ، ووليد ساعده بتعطيل الطباعة والأرشفة وسحب النسخة.', 'ريهام أخطأت في تسمية العينة؛ أدهم نسي إغلاق درج الطباعة؛ نانسي ضغطت لتسريع النتيجة.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-04', 'اختفاء دليل', 'السلاح بلا بصمات', 'تُعثر أداة الجريمة بعد مسح بصماتها، ما يعني أن أحدهم وصل إلى الدليل بعد الواقعة.', 3, 1, 'عمران', 'السلاح وُجد لكنه لا يحمل الآثار الطبيعية المتوقعة؛ أكثر من شخص لمس أو اقترب من المكان قبل تثبيته؛ ما حدث قد يكون تسترًا أو مجرد ارتباك من شخص خائف.', 'أحد الموجودين بقي وحده في محيط المكان؛ شخص آخر اعترف جزئيًا أنه لمس السلاح؛ هناك شاهد رأى حركة متأخرة بعد الجريمة لكن وصفه غير حاسم.', 'مادة التنظيف أو المسح من النوع المتاح في أكثر من مكان؛ التوقيت الذي اختفت فيه البصمات لا يمكن حصره بالدقيقة؛ جميع الموجودين لديهم سبب لإخفاء جزء من تحركهم.', 'عمران محا البصمات بعد الواقعة ليحمي شخصًا يعرفه، مستفيدًا من موقعه كأول من وصل.', 'قتيبة لمس السلاح قبل وصول التثبيت الرسمي؛ سلوى رأت شخصًا يهرب وخافت أن تتورط.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-05', 'اختفاء دليل', 'العقد الناقص', 'الصفحة الأخيرة من عقد شراكة تختفي قبل جلسة نزاع مالي حاسمة.', 5, 2, 'لؤي، رانيا', 'الصفحة المفقودة هي الجزء الوحيد الذي يحسم نسب الأرباح؛ أكثر من شخص اطّلع على العقد؛ إخفاء الصفحة قد ينقذ طرفًا من خسارة أو يخفي خطأ في إعداد العقد.', 'أحد اللاعبين أخرج العقد من مكان الحفظ؛ شخص آخر كان يراجع نسخة مختلفة؛ يوجد ارتباك قديم حول النسخ الأصلية وغير المكتملة.', 'آثار تمزيق أو استبدال ظهرت؛ تصوير جزء من العقد على هاتف أحد اللاعبين يحرّك الشك نحوه؛ كل طرف لديه سبب ليقول إنه خاف مما في الصفحة.', 'لؤي دبّر اختفاء الصفحة لأنها كانت ستخسره النزاع، ورانيا سحبت النسخة الأصلية وأخفت الصفحة بتنسيق معه.', 'ديمة كانت تحتفظ بنسخة غير موقعة؛ مراد عدّل ملفًا ماليًا قديمًا؛ حسام تأخر في مراجعة العقد.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-06', 'اختفاء دليل', 'تسجيل الممر', 'تسجيل كاميرا ممر داخلي يختفي فقط في اللحظة التي مر فيها شخص مهم.', 5, 2, 'ربيع، زهير', 'الاختفاء طال دقائق محددة فقط؛ أكثر من شخص يعرف ضعف التغطية في ذلك الممر؛ حذف هذه الدقيقة قد يخدم أكثر من طرف.', 'أحد اللاعبين دخل إلى نظام المراقبة؛ شخص آخر غيّر توزيع التغطية أو نوبة المتابعة؛ الموظف الذي يظهر في التسجيل محل شك أصلاً.', 'هناك نسخة محذوفة جزئيًا يمكن استعادتها؛ كل من في محيط الممر لديه رواية ناقصة؛ ما يبدو كإخفاء لشخص واحد قد يكون تسترًا على سلسلة أفعال.', 'ربيع حذف أو عطّل الجزء الحساس من التسجيل، وزهير ساعده بتغيير المتابعة لأن المقطع كان سيدينهما في واقعة سابقة.', 'أمل كانت تحاول إخفاء مخالفة إدارية؛ شادي تهرب من مواجهة داخلية؛ فاطنة مرّت بالممر في وقت حرج.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-07', 'اختفاء دليل', 'الرسالة الورقية', 'يُعثر على ظرف مفتوح، لكن الرسالة التي كانت بداخله اختفت.', 3, 1, 'جمانة', 'الظرف وصل فعلًا لكن لا أحد يتفق على من قرأ الرسالة أولًا؛ اختفاء الرسالة قد يكون لحماية الضحية أو الجاني أو شخص ثالث؛ كل من حول الضحية يخشى محتواها لأسباب مختلفة.', 'أحد اللاعبين استلم البريد يدويًا قبل وضعه؛ شخص آخر دخل المكتب بعد وصول الرسالة بوقت قصير؛ هناك توتر سابق حول مستندات ورسائل أخرى.', 'بقايا ورق أو مسودة تشبه الرسالة ظهرت؛ اختلاف بين من يقول إنها كانت تهديدًا ومن يقول إنها كانت تحذيرًا؛ كل طرف لديه دافع مختلف لمنع الآخرين من قراءة الرسالة.', 'جمانة أخفت الرسالة لأنها كانت ستكشف تلاعبها الإداري وربما تربطها مباشرة بسلسلة قرارات مشبوهة.', 'فارس كان يفتش في أدراج والده؛ بلال نقل بعض المستندات بين المكتب والسيارة دون إذن.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-08', 'اختفاء دليل', 'ختم الحضور', 'تختفي ورقة حضور اجتماع مهم كانت قادرة على إثبات من كان في المبنى وقت الواقعة.', 5, 2, 'باسط، مجدي', 'الورقة اختفت بعد الاجتماع مباشرة؛ أكثر من شخص تعامل معها؛ وجودها أو غيابها قد يدين شخصًا ويحمي آخر.', 'أحد اللاعبين نقل الورقة من القاعة إلى مكتب آخر؛ شخص آخر كان يسأل عنها بتوتر؛ بعض الحاضرين لم يوقعوا بطريقة سليمة.', 'كاميرا الاستقبال أو حركة الملفات تشير إلى انتقال الورقة؛ كل رواية عن آخر من لمسها تتعارض مع الأخرى؛ الدافع لإخفائها ليس قانونيًا فقط بل شخصي وإداري.', 'باسط أخفى ورقة الحضور لأنها كانت ستثبت وجوده مع طرف لا يجب أن يظهر، ومجدي ساعده عبر تمرير الملف بعيدًا عن المسار المعتاد.', 'شروق أخطأت في تدوين بعض الأوقات؛ تميم خرج دون توقيع واضح؛ هالة صورت جزءًا من الورقة.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-09', 'اختفاء دليل', 'صورة الهاتف', 'شاهد يؤكد أنه التقط صورة مهمة، لكن الصورة حُذفت قبل أن تصل للمحققين.', 3, 1, 'مهيب', 'الصورة التُقطت فعلًا لكن اختفت لاحقًا؛ الهاتف مرّ على أكثر من يد؛ اختفاء الصورة قد يكون لحماية صاحبها من التورط أو لحماية شخص ظهر فيها.', 'أحد اللاعبين طلب فحص الهاتف أو لمسه بحجة المساعدة؛ شخص آخر حاول إقناع الشاهد بعدم تسليم الصورة؛ الروايات تختلف حول مدى وضوح الصورة.', 'بقايا ملف مصغر أو أثر رقمي يؤكد وجود الصورة؛ الوصول للهاتف لم يكن مقتصرًا بالكامل على شخص واحد؛ لكل لاعب سبب معقول لقول إنه لم يرد المشكلة.', 'مهيب حذف الصورة بعد أن وصلته فرصة فحص الهاتف، بطلب أو لمصلحة تخص شخصًا كان سيظهر في اللقطة.', 'حسام كذب في وصف زاوية التصوير؛ داليا طلبت منه ألا يسلّم الصورة خوفًا عليه.', 'production_ready', 'ar-EG');
INSERT INTO cases (case_code, crime_type, title, intro, player_count, mafioso_count, mafioso_names, round_1_evidence, round_2_evidence, round_3_evidence, final_truth, innocent_secrets, status, language) VALUES ('E-10', 'اختفاء دليل', 'الظرف الأزرق', 'يضع الجد مستندًا مهمًا داخل ظرف أزرق على مكتبه، وبعد وفاته مباشرة يختفي الظرف.', 5, 2, 'هيثم، نهلة', 'الظرف كان ظاهرًا مساءً؛ اختفاؤه يفيد شخصًا من العائلة لكنه قد يحرج أيضًا المحامي أو من كان يفتش في الأوراق؛ لون الظرف وطبيعته جعلاه سهل التمييز والإخفاء.', 'أحد اللاعبين دخل الغرفة منفردًا بعد الوفاة؛ شخص آخر سأل عن الظرف أكثر من مرة؛ أوراق قديمة أخرى كانت محل بحث في الليلة نفسها.', 'آثار من الورق أو المغلف ظهرت في مكان غير متوقع؛ كل من بالعائلة لديه تفسير مختلف لما كان يتوقعه داخل الظرف؛ بعض روايات الدخول والخروج من الغرفة لا تتفق.', 'هيثم أخفى الظرف لأنه كان يغيّر توزيع التركة أو يكشف أمرًا يضر بمصلحته، ونهلة ساعدته في الوصول إليه وإبعاده عن الأنظار.', 'مروى كانت تبحث عن خطاب شخصي؛ عماد أخفى وصية أقدم؛ شريف دخل الغرفة سرًا لأنه ظن أن الجد ترك له شيئًا منفصلًا.', 'production_ready', 'ar-EG');
